786: bool HttpConnectionManagerConfig::createUpgradeFilterChain(
787:     absl::string_view upgrade_type,
788:     const Http::FilterChainFactory::UpgradeMap* per_route_upgrade_map,
789:     Http::FilterChainManager& callbacks) const {
790:   bool route_enabled = false;
791:   if (per_route_upgrade_map) {
792:     auto route_it = findUpgradeBoolCaseInsensitive(*per_route_upgrade_map, upgrade_type);
793:     if (route_it != per_route_upgrade_map->end()) {
794:       // Upgrades explicitly not allowed on this route.
795:       if (route_it->second == false) {
796:         return false;
797:       }
798:       // Upgrades explicitly enabled on this route.
799:       route_enabled = true;
800:     }
801:   }
802: 
803:   auto it = findUpgradeCaseInsensitive(upgrade_filter_factories_, upgrade_type);
804:   if ((it == upgrade_filter_factories_.end() || !it->second.allow_upgrade) && !route_enabled) {
805:     // Either the HCM disables upgrades and the route-config does not override,
806:     // or neither is configured for this upgrade.
807:     return false;
808:   }
809:   const FilterFactoriesList* filters_to_use = &filter_factories_;
810:   if (it != upgrade_filter_factories_.end() && it->second.filter_factories != nullptr) {
811:     filters_to_use = it->second.filter_factories.get();
812:   }
813: 
814:   Http::FilterChainUtility::createFilterChainForFactories(
815:       callbacks, Http::EmptyFilterChainOptions{}, *filters_to_use);
816:   return true;
817: }
