955: void ConnectionManagerImpl::ActiveStream::chargeStats(const ResponseHeaderMap& headers) {
956:   uint64_t response_code = Utility::getResponseStatus(headers);
957:   filter_manager_.streamInfo().setResponseCode(response_code);
958: 
959:   if (filter_manager_.streamInfo().health_check_request_) {
960:     return;
961:   }
962: 
963:   // No response is sent back downstream for internal redirects, so don't charge downstream stats.
964:   const absl::optional<std::string>& response_code_details =
965:       filter_manager_.streamInfo().responseCodeDetails();
