967:       response_code_details == Envoy::StreamInfo::ResponseCodeDetails::get().InternalRedirect) {
968:     return;
969:   }
970: 
971:   connection_manager_.stats_.named_.downstream_rq_completed_.inc();
972:   connection_manager_.listener_stats_.downstream_rq_completed_.inc();
973:   if (CodeUtility::is1xx(response_code)) {
974:     connection_manager_.stats_.named_.downstream_rq_1xx_.inc();
975:     connection_manager_.listener_stats_.downstream_rq_1xx_.inc();
976:   } else if (CodeUtility::is2xx(response_code)) {
977:     connection_manager_.stats_.named_.downstream_rq_2xx_.inc();
978:     connection_manager_.listener_stats_.downstream_rq_2xx_.inc();
979:   } else if (CodeUtility::is3xx(response_code)) {
980:     connection_manager_.stats_.named_.downstream_rq_3xx_.inc();
981:     connection_manager_.listener_stats_.downstream_rq_3xx_.inc();
982:   } else if (CodeUtility::is4xx(response_code)) {
983:     connection_manager_.stats_.named_.downstream_rq_4xx_.inc();
984:     connection_manager_.listener_stats_.downstream_rq_4xx_.inc();
985:   } else if (CodeUtility::is5xx(response_code)) {
986:     connection_manager_.stats_.named_.downstream_rq_5xx_.inc();
